import tempfile, os
from dspy.clients.cache import Cache

# Compare on-disk size for a large, compressible value with vs without compression.
value = {'text': 'The quick brown fox jumps over the lazy dog. ' * 5000}

sizes = {}
for codec in [None, 'gzip', 'zlib']:
    d = tempfile.mkdtemp()
    c = Cache(True, False, d, 1024*1024*50, 1000, compress=codec)
    req = {'k': 'v'}
    c.put(req, value)
    c.disk_cache.close() if hasattr(c.disk_cache, 'close') else None
    total = 0
    for root, dirs, files in os.walk(d):
        for f in files:
            total += os.path.getsize(os.path.join(root, f))
    sizes[codec] = total

print(sizes)
assert sizes['gzip'] < sizes[None]
assert sizes['zlib'] < sizes[None]
print('compression reduces on-disk size: OK')
